var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"하아아앗-!!","JPN":"はあああーっ！！","ENG":"Haaaaa!!!!","TWN":"哈啊啊啊啊！！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KNIGH_PRIDE_NULL_A","text":{"KOREA":"저 녀석. 연무장 때랑은 뭔가 다른 것 같지 않아?","JPN":"あいつ、訓練場の時とはなんか違うと思わないか？","ENG":"Hey, doesn't she seem different from how she was back in the training hall?","TWN":"那傢伙。和在演武場時有什麼不一樣，不是嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"KNIGH_PRIDE_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGH_PRIDE_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"KNIGH_PRIDE_NULL_B","text":{"KOREA":"네 눈은 옹이구멍이냐? 검을 휘두르는 동작 자체가 달라졌잖아.","JPN":"あんたの目は節穴か？　剣を振り回す動作自体が以前とは違っているじゃないか。","ENG":"Are your eyes just for show? Even the way she swings her sword is completely different.","TWN":"你的眼睛是木頭做的嗎？揮劍的動作都已經不一樣了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"KNIGH_PRIDE_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGH_PRIDE_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"KNIGH_PRIDE_NULL_B","text":{"KOREA":"그레이스 경이 봐주셨다지만 며칠 만에 저렇게 되다니… 나 같은 범재는 벽을 느끼는구만.","JPN":"グレース卿が鍛えてくださったとは言え、数日であんなになるなんて……俺みたいな凡才は壁を感じるなあ。","ENG":"Dame Grace may be training her, but this kind of improvement in just a few days? Makes someone like me feel hopeless.","TWN":"雖然是經過葛瑞絲小姐的訓練，但幾天之內就能變成這樣……像我這樣的凡人真是感受到差距了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"KNIGH_PRIDE_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGH_PRIDE_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"KNIGH_PRIDE_NULL_A","text":{"KOREA":"그래서, 지켜만 보게?","JPN":"で、ただ見てるだけなのか？","ENG":"So, what, you just gonna sit there?","TWN":"所以，就這樣看著嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"KNIGH_PRIDE_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGH_PRIDE_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"KNIGH_PRIDE_NULL_B","text":{"KOREA":"설마. 오늘은 누가 더 괴수를 많이 때려잡나 승부다!","JPN":"まさか。今日は誰が怪獣をもっと多く倒せるか、勝負だ！","ENG":"Heck no. Let's make it a bet to see who slays more monsters!","TWN":"怎麼可能，來看看今天誰殺比較多怪！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"KNIGH_PRIDE_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGH_PRIDE_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"KNIGH_PRIDE_NULL_B","text":{"KOREA":"뒤처진 녀석들의 저녁은, 아주 조촐할 줄 알아!","JPN":"少ないやつらの夕飯は、肉抜きだ。","ENG":"The loser gets the smallest portion for dinner!","TWN":"輸的人晚餐就只能用醬油拌飯！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"KNIGH_PRIDE_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGH_PRIDE_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"지칠 법한 연속된 전투 속에서도 단 한 명의 존재가 병사들의 사기를 북돋우고 있다.","JPN":"うんざりするほどに続く戦闘の中でも、たった一人の存在が兵士の士気を上げている。","ENG":"Even after constant battles, just one person is enough to lift the entire unit's morale.","TWN":"在令人疲憊的連續戰鬥中，只有一個人能夠激勵士兵們的士氣。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"그레이스 경의 부재가 전세에 큰 영향을 끼치지 않을까 싶었으나… 기우였군.","JPN":"グレース卿の不在が戦況に影響するのではと思ったが……杞憂だったな。","ENG":"I thought Dame Grace's absence would tip the scales... but I was clearly wrong.","TWN":"我原以為葛瑞絲卿的缺席會對戰局產生重大影響……看來是杞人憂天了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"페론 경! 괴수들이 물러가기 시작합니다!","JPN":"ペロン卿！　怪獣が退き始めています！","ENG":"Sir Ferron! The monsters are retreating!","TWN":"費隆卿！怪獸們開始撤退了！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"제가 진입할 테니 좌익과 우익을 선회하세요! 빠져나온 비행형은 딜란 경이 맡습니다!","JPN":"私が突入しますので、左翼と右翼は旋回してください！　抜け出た飛行型はディラン卿が担当してください！","ENG":"I'm heading in! Flank them from both sides! Sir Dylan, handle the fliers that broke away!","TWN":"我會加入，你們負責左翼和右翼的迂回！逃出來的飛行型由迪蘭負責！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"전군, 돌격-!!","JPN":"全軍、突撃！！","ENG":"Knights, charge!","TWN":"全軍，出擊-！！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"KNIGHT_PRIDE_NULL_NULL","text":{"KOREA":"크아-! 설마 이번 원정이 이렇게 순조로울 줄이야!","JPN":"くうー！　まさか今回の遠征がここまで順調とは！","ENG":"Hah! Who would've thought this mission would actually go well?!","TWN":"哇-！ 沒想到這次遠征會如此順利！"},"stage":{"bg":"CAMP_NIGHT","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"KNIGHT_PRIDE_NULL_NULL","text":{"KOREA":"피해도 최소화하고 있으니, 어쩌면 다 같이 돌아가는 것도 꿈이 아니겠어!","JPN":"被害も最少限に抑えられているし、みんなで帰るのも夢ではないかもな！","ENG":"Minimal casualties too. Maybe, just maybe, we'll all make it back alive!","TWN":"既然已經將損失降到最低，也許大家一起回去也不是夢！"},"stage":{"bg":"CAMP_NIGHT","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KNIGHT_PRIDE_NULL_NULL","text":{"KOREA":"예상보다 많이 살아남은 탓에 식량문제는 있지만 말이야, 하하!!","JPN":"予想より多く生き残っているせいで、食糧問題はあるけどな、はは！！","ENG":"Only problem now is food with more survivors than we planned for, haha!","TWN":"雖然比預想中活下來的人多會導致糧食問題，哈哈！！"},"stage":{"bg":"CAMP_NIGHT","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":null,"text":{"KOREA":"그렇다고 채식이 말입니까? 싸울려면 고기를 먹어야죠!","JPN":"だからって野菜ばかり食べろっていうんですか！　戦うためには肉を食べないと！","ENG":"What, so we're going vegetarian now?! We need meat to fight!","TWN":"所以是要吃素嗎？不吃肉怎麼有體力作戰！"},"stage":{"bg":"CAMP_NIGHT","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":null,"text":{"KOREA":"맞습니다! 연회도 아닌데 뭔 놈의 술만 이렇게 가져오셨어요?","JPN":"そうです！　宴会しに来たんじゃないのに、誰が酒ばっかりこんなに持ってきたんですか！","ENG":"Seriously! Why'd we bring so much booze and no food?","TWN":"沒錯！又不是宴會，怎麼帶了這麼多酒來？"},"stage":{"bg":"CAMP_NIGHT","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"KNIGHT_PRIDE_NULL_NULL","text":{"KOREA":"시끄러워, 인마! 토벌 수를 기준으로 저녁을 나누자고 한 게 누구인데?","JPN":"うるせえ！　討伐した数に応じて夕飯の量を決めようって言ったのはどこのどいつだ！","ENG":"Shut it! You're the one who said dinner would be based on monster kills!","TWN":"吵死了，混蛋！是誰提議根據殺怪數來分配晚餐的？"},"stage":{"bg":"CAMP_NIGHT","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"KNIGHT_PRIDE_NULL_NULL","text":{"KOREA":"나도 안주 없이 술만 먹고 있잖아! 부족하면 저기 가서 풀이나 뜯어 먹어!","JPN":"俺だってつまみなしで酒飲んでるんだ！　足りなかったらあそこで草でも食べてろ！","ENG":"I'm stuck drinking with nothing to eat too! If you're hungry, go chew on some grass!","TWN":"我也在沒有下酒菜只能喝酒！不夠的話就去那裡吃草吧！"},"stage":{"bg":"CAMP_NIGHT","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"식사가 부족하시다면 제 음식을 나눠드리겠습니다.","JPN":"食事が足りないのでしたら、私の分をお分けします。","ENG":"If food is short, I'd be happy to share mine.","TWN":"如果你食物不夠，我可以分給你一些我的食物。"},"stage":{"bg":"CAMP_NIGHT","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"다른 분들 말은 신경 쓰실 필요 없습니다. 식량배분조차 전쟁에선 중요한 요소니까요.","JPN":"他の方々の発言は気にする必要ありません。食糧分配も戦争では重要な要素ですから。","ENG":"No need to worry. Rationing's part of the fight too.","TWN":"不用在意其他人的話。在戰爭中，糧食分配也很重要。"},"stage":{"bg":"CAMP_NIGHT","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"경께서 굶으면 크나큰 전력 손실인 만큼, 저희를 위한다면 배불리 먹고 힘을 비축해 두세요.","JPN":"卿が空腹だと大変な戦力損失になります。私たちのためにもお腹いっぱい食べて力を貯めてください。","ENG":"You're a key asset. If you go hungry, that's a loss for all of us. Do us a favor and eat your fill.","TWN":"你若是餓著肚子，那可是巨大的戰力損失。為了我們，請吃飽飯，儲備力量吧。"},"stage":{"bg":"CAMP_NIGHT","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……예. 감사합니다, 페론 경.","JPN":"……はい、ありがとうございます、ペロン卿。","ENG":"...Understood. Thank you, Sir Ferron.","TWN":"……好的。謝謝你，費隆卿。"},"stage":{"bg":"CAMP_NIGHT","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"하지만 식량문제는 사기와 직결되는 중요한 요소라는 것 또한 엄연한 사실.","JPN":"ですが、食糧問題は士気に繋がる重要な要素だということもまた事実です。","ENG":"Still, food shortage is no joke. It hits morale hard.","TWN":"但是糧食問題確實是與士氣直接相關的重要因素。"},"stage":{"bg":"CAMP_NIGHT","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};